mapper.update:
UPDATE item_class
SET item_class_code = #{code}
  , item_class_name = #{name}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE item_class_id = #{id}

UPDATE item_category
SET item_category_code = #{code}
  , item_category_name = #{name}
  , updated_at         = NOW()
  , updated_user_id    = #{sessionUserId}
WHERE item_category_id = #{id}

UPDATE item
SET item_code       = #{code}
  , item_name       = #{name}
  , no_use          = #{noUse}
  , item_desc       = #{itemDesc}
  , ref_m_min       = #{refMmin}
  , ref_m_max       = #{refMmax}
  , ref_f_min       = #{refFmin}
  , ref_f_max       = #{refFmax}
  , ref_unit        = #{refUnit}
  , result_use      = #{resultUse}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE item_id = #{id}

UPDATE item_sub
SET item_sub_code   = #{code}
  , item_sub_name   = #{name}
  , no_use          = #{noUse}
  , ref_m_min       = #{refMmin}
  , ref_m_max       = #{refMmax}
  , ref_f_min       = #{refFmin}
  , ref_f_max       = #{refFmax}
  , ref_unit        = #{refUnit}
  , result_use      = #{resultUse}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE item_sub_id = #{id}

UPDATE item_class
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE item_class_id = #{id}

UPDATE item_category
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE item_category_id = #{id}

UPDATE item
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
